					/>
				)}
			</pre>
			{content.length > 500 && (
				<button
					onClick={() => setIsTruncated(!isTruncated)}
					style={{
						marginTop: '0.5rem',
						padding: '0.5rem 1rem',
						backgroundColor: '#3b82f6',
						color: 'white',
						border: 'none',
						borderRadius: '4px',
						cursor: 'pointer',
						fontSize: '0.875rem',
					}}
				>
					{isTruncated ? 'Show more' : 'Show less'}
				</button>
			)}
		</div>
	);
};

